function sql(strings, ...keys) {
	let i = 0;
	let str = strings[i];
	while (i < keys.length) {
		str += keys[i++].replace(/'/g, "''");
		str += strings[i];
	}
	return str;
}

const lines = rawStr.split("\n");
let i = 0;
while (i < lines.length) {
	let line = lines[i++];
	if (!/^Recipe;/.test(line))
		continue;
	while (i < lines.length) {
		if (/^ *$/.test(lines[i]))
			break;
		const [recipe, skill, cost, sellback, ingredients, level, notes, duration, charges, value, range, damage, recast] = lines[i++].split(';');
		console.log(sql`INSERT INTO rawCraft (recipe, skill, cost, sell_back, ingredients, level, item_notes, duration, charges, value, range, damage, recast) VALUES ('${recipe}','${skill}','${cost}','${sellback}','${ingredients}','${level}','${notes}','${duration}','${charges}','${value}','${range}','${damage}','${recast}');`);
	}
}
